const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// Security Review: API keys hardcoded in source code - This is insecure for production
// In production, these should be retrieved from Key Vault or Azure App Configuration
const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token_here'; // This should also be secured

sgMail.setApiKey(SENDGRID_API_KEY);

module.exports = async function (context, req) {
    context.log('JavaScript HTTP trigger function processed a request.');

    if (!req.body) {
        context.res = {
            status: 400,
            body: "Please pass a request body"
        };
        return;
    }

    const { email, phone, message } = req.body;

    try {
        // Send email via SendGrid
        if (email) {
            const msg = {
                to: email,
                from: 'noreply@demo.com',
                subject: 'Test Email',
                text: message,
                html: `<p>${message}</p>`,
            };
            await sgMail.send(msg);
        }

        // Send SMS via Twilio
        if (phone) {
            const client = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);
            await client.messages.create({
                body: message,
                from: '+1234567890',
                to: phone
            });
        }

        context.res = {
            status: 200,
            body: "Email and/or SMS sent successfully"
        };
    } catch (error) {
        context.log.error('Error sending message:', error);
        context.res = {
            status: 500,
            body: "Error sending message"
        };
    }
};